#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, C, Q, A, B, D;
        scanf("%d %d %d %d %d %d", &N, &C, &Q, &A, &B, &D);
        int* skill = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N && i < 10000; i++) {
            scanf("%d", &skill[i]);
        }
        for (int i = 10000; i < N; i++) {
            skill[i] = (A * skill[i-1] + B * skill[i-2] + D) % 230;
        }
        int* cand = (int*)malloc((N + 1) * sizeof(int));
        for (int K = 1; K <= N; K++) {
            cand[K] = 0;
            for (int i = 0; i <= N - K; i++) {
                int min = skill[i];
                int max = skill[i];
                for (int j = i + 1; j < i + K; j++) {
                    if (skill[j] < min) min = skill[j];
                    if (skill[j] > max) max = skill[j];
                }
                if (max - min <= C) cand[K]++;
            }
        }
        for (int i = 0; i < Q; i++) {
            int M;
            scanf("%d", &M);
            int max_cand = 0;
            int best_K = 1;
            for (int K = 1; K <= N; K++) {
                if (cand[K] <= M && cand[K] > max_cand) {
                    max_cand = cand[K];
                    best_K = K;
                }
            }
            printf("%d %d\n", best_K, max_cand);
        }
        free(skill);
        free(cand);
    }
    return 0;
}

